const m = $json;

// Pull mapping from the Set node
const cfg = {
  dbId:$('Config').first().json.db.thought_log.id,
  properties: {
    title: { name: "Thought ID", type: "title" },
    archived: { name: "Archived", type: "checkbox" },
    capturedDate: { name: "Captured Date", type: "date" },
    confidence: { name: "Confidence", type: "number" },
    intent: { name: "Intent", type: "select" },
    routedToSignalDesk: { name: "Routed to SignalDesk", type: "checkbox" },
    sensitivity: { name: "Sensitivity", type: "select" },
    source: { name: "Source", type: "select" },
    sourceUrl: { name: "Source URL", type: "url" },
    urgencyHint: { name: "Urgency Hint", type: "select" },
    dailySummary: { name: "Daily Summary", type: "relation" },
    decisions: { name: "Decisions", type: "relation" },
    entities: { name: "Entities", type: "relation" },
    signals: { name: "Signals", type: "relation" },
    sourceEventId: { name: "Source Event ID", type: "rich_text" },
    author: { name: "Author", type: "rich_text" },
    rawText: { name: "Raw Text", type: "rich_text" },
    normalizedText: { name: "Normalized Text", type: "rich_text" }
  },
  defaults: {
    sourceSelect: "Slack",
    intentSelect: "Other",
    urgencySelect: "Normal",
    sensitivitySelect: "Professional",
    archived: false,
    routedToSignalDesk: false
  }
};

const P = cfg.properties;
const D = cfg.defaults;

// Slack fields (from your Slack Trigger)
const channel_id = (m.channel || "").toString();
const user_id = (m.user || "").toString();
const text = (m.text || "").toString();

const ts = (m.ts || "").toString();
const event_ts = (m.event_ts || "").toString();
const client_msg_id = (m.client_msg_id || "").toString();

// Prefer client_msg_id for dedupe
const source_event_id = client_msg_id
  ? `slack:msg:${channel_id}:${client_msg_id}`
  : `slack:msg:${channel_id}:${ts || event_ts}`;

// Deterministic thought id
const thought_id = client_msg_id
  ? `th_${channel_id}_${client_msg_id}`
  : `th_${channel_id}_${ts || event_ts}`;

// Lisbon local date (requires n8n host TZ=Europe/Lisbon)
const captured_date = new Date().toLocaleDateString("en-CA"); // YYYY-MM-DD

// Helper to build Notion property objects by type
function notionProp(type, value) {
  if (value === undefined || value === null) return null;

  switch (type) {
    case "title":
      return { title: [{ text: { content: String(value) } }] };
    case "rich_text":
      return { rich_text: [{ text: { content: String(value) } }] };
    case "select":
      return { select: { name: String(value) } };
    case "number":
      return { number: Number(value) };
    case "checkbox":
      return { checkbox: Boolean(value) };
    case "url":
      return { url: String(value) };
    case "date":
      return { date: { start: String(value) } };
    default:
      // relations handled elsewhere; ignore here
      return null;
  }
}

// Build Notion properties using the mapping
const properties = {};

// Title
properties[P.title.name] = notionProp(P.title.type, thought_id);

// Core fields
properties[P.source.name] = notionProp(P.source.type, D.sourceSelect);
properties[P.capturedDate.name] = notionProp(P.capturedDate.type, captured_date);
properties[P.archived.name] = notionProp(P.archived.type, D.archived);
properties[P.routedToSignalDesk.name] = notionProp(P.routedToSignalDesk.type, D.routedToSignalDesk);

// Optional classification defaults (safe if these selects exist)
properties[P.intent.name] = notionProp(P.intent.type, D.intentSelect);
properties[P.urgencyHint.name] = notionProp(P.urgencyHint.type, D.urgencySelect);
properties[P.sensitivity.name] = notionProp(P.sensitivity.type, D.sensitivitySelect);

// Capture metadata + text (these must exist in Notion or Notion will 400)
properties[P.sourceEventId.name] = notionProp(P.sourceEventId.type, source_event_id);
properties[P.author.name] = notionProp(P.author.type, user_id);
properties[P.rawText.name] = notionProp(P.rawText.type, text.slice(0, 1900));
properties[P.normalizedText.name] = notionProp(P.normalizedText.type, text.trim().slice(0, 1900));

// Optional permalink -> map to Source URL if you add it later
// If you add a Slack permalink fetch node, set m.permalink and uncomment:
// properties[P.sourceUrl.name] = notionProp(P.sourceUrl.type, m.permalink);

// Remove null props (important)
for (const k of Object.keys(properties)) {
  if (properties[k] === null) delete properties[k];
}

// Final Notion create page payload
const notion_payload = {
  parent: { database_id: cfg.dbId },
  properties
};

// Slack context for SD
const slack_ctx = {
  channel_id,
  message_ts: ts || event_ts,
  thread_ts: (m.thread_ts || m.threadTs || ts || event_ts || "").toString(),
  captured_by_user_id: user_id,
  raw_text: text,
  normalized_text: text.trim(),
  slack: {
    team_id: (m.team || "").toString(),
    channel_id,
    channel_type: (m.channel_type || "").toString(),
    user_id,
    client_msg_id
  }
};

return [{
  source_event_id,
  thought_id,
  captured_date,
  notion_payload,
  slack_ctx
}];

const slackCtx = $node["Build Payloads"].json.slack_ctx;
const text = (slackCtx?.normalized_text || '').toString();

const notionPageId = $node["HTTP Request - Notion"].json.id;
const notionUrl = $node["HTTP Request - Notion"].json.url;

const cleaned = text.replace(/^(!|sd:)\s*/i, '').trim();

let cognitionType = 'signal';
if (/^task:/i.test(text)) cognitionType = 'task_hint';
if (/^risk:/i.test(text)) cognitionType = 'risk';
if (/^blocker:/i.test(text)) cognitionType = 'blocker';
if (/^decision:/i.test(text)) cognitionType = 'decision';

const sd_payload = {
  source: 'slack',
  source_event_id: $node["Build Payloads"].json.source_event_id,
  cognitionType,
  title: cleaned.slice(0, 180),
  body: cleaned.slice(0, 5000),
  externalThoughtIds: [$node["Build Payloads"].json.thought_id],
  externalRefs: {
    notion: { pageId: notionPageId, url: notionUrl },
    slack: {
      channel: slackCtx?.channel_id,
      ts: slackCtx?.message_ts,
      user: slackCtx?.captured_by_user_id
    }
  }
};

return [{ sd_payload }];

