parameters.jsCode:
// Input = OpenAI router output
const r = $json;

// Pull from Build Payloads
const bp = $node["Build Payloads"].json;

// UTC timestamp + HHmm suffix for filename
const now = new Date();
const iso = now.toISOString();
const hhmm = iso.slice(11, 13) + iso.slice(14, 16); // "HHmm" in UTC
const date = bp.captured_date; // YYYY-MM-DD (Lisbon)

// Slack text/context
const text =
  bp.slack_ctx?.normalized_text ||
  bp.slack_ctx?.raw_text ||
  "";

const channel = bp.slack_ctx?.channel_id || "";
const user = bp.slack_ctx?.captured_by_user_id || "";
const sourceEventId = bp.source_event_id || "";

// Escape helper
const esc = (s) => (s ?? "").toString().replace(/\r/g, "");

// Build routes block
const routes = Array.isArray(r.routes) ? r.routes : [];

const routeLines = routes.map(x => {
  const title = x?.record?.title || "";
  const tags = Array.isArray(x?.record?.tags) ? x.record.tags.join(", ") : "";

  return `  - db: ${x.db}
    title: ${esc(title)}
    mode: ${x.mode}
    confidence: ${Number(x.confidence || 0).toFixed(2)}
    dedupe_key: ${x.dedupe_key}${tags ? `\n    tags: [${tags}]` : ""}`;
}).join("\n");

// Markdown append block
const md_append =
`---
- ts: ${iso}
  source: slack
  channel: ${channel}
  user: ${user}
  id: ${sourceEventId}
  text: |
    ${esc(text).split("\n").join("\n    ")}
  routes:
${routeLines || "  []"}
  reason: ${esc(r.reason || "")}
`;

// File name/path (per-message file)
const md_filename = `${date}-${hhmm}.md`;
const md_path = `daily/${md_filename}`;

// Return n8n item
return [
  {
    json: {
      md_path,
      md_filename,
      md_append,
      routes: r.routes || [],
      reason: r.reason || ""
    }
  }
];
